const t={hostControl:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Управляйте Linux-хостом принтера — проверяйте его состояние и состояние операционной системы. Службы, очистка диска и системные настройки появятся в следующих фазах."}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"Что это?"}},body:{t:0,b:{t:2,i:[{t:3}],s:"FilaMind работает на небольшом Linux-компьютере принтера (хосте). Эта панель показывает текущее состояние этой машины и её ОС, чтобы вы замечали проблемы — перегрев процессора, заполненный диск, несинхронизированные часы — не открывая терминал."}},step1:{t:0,b:{t:2,i:[{t:3}],s:"Бегло просматривайте карточки температуры процессора, памяти, диска и сети."}},step2:{t:0,b:{t:2,i:[{t:3}],s:"Следите за таблицей самых нагружающих процессов, чтобы видеть, что использует процессор сейчас."}},step3:{t:0,b:{t:2,i:[{t:3}],s:"Оставьте автообновление включённым для живого вида или отключите его и обновляйте вручную."}},topics:{glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Используемые здесь термины"}}},monitor:{title:{t:0,b:{t:2,i:[{t:3}],s:"Чтение монитора"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Здесь всё только для чтения. Полосы становятся янтарными после 75 % и красными после 90 %. Температура процессора становится янтарной при 70 °C и красной при 80 °C. Предупреждение о троттлинге появляется только на платах, которые его сообщают (в основном Raspberry Pi)."}}}},glossary:{host:{term:{t:0,b:{t:2,i:[{t:3}],s:"Хост"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Небольшой Linux-компьютер (например, Raspberry Pi или BTT CB1), на котором работают Klipper, Moonraker и FilaMind — отдельный от микроконтроллеров принтера."}}},load:{term:{t:0,b:{t:2,i:[{t:3}],s:"Средняя нагрузка"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Сколько процессов ожидали выполнения, усреднённо за 1 / 5 / 15 минут. Грубо: значение около числа ядер означает, что процессор занят; значительно выше — что он перегружен."}}},swap:{term:{t:0,b:{t:2,i:[{t:3}],s:"Подкачка (swap)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Дисковое пространство, используемое как резерв, когда заканчивается ОЗУ. Активное использование подкачки замедляет хост — признак нехватки памяти."}}},throttle:{term:{t:0,b:{t:2,i:[{t:3}],s:"Троттлинг"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Когда плата снижает скорость, чтобы защитить себя — обычно из-за слабого питания (просадка напряжения) или перегрева. Сообщается в основном на Raspberry Pi."}}},ntp:{term:{t:0,b:{t:2,i:[{t:3}],s:"NTP / синхронизация часов"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Протокол сетевого времени поддерживает точность часов хоста. Несинхронизированные часы могут нарушить таймлапсы, журналы и TLS-сертификаты."}}},locale:{term:{t:0,b:{t:2,i:[{t:3}],s:"Локаль"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Настройки языка и раскладки клавиатуры хоста, используемые ОС для текста, дат и раскладки клавиатуры консоли."}}}}},monitor:{refresh:{t:0,b:{t:2,i:[{t:3}],s:"Обновить"}},autoRefresh:{t:0,b:{t:2,i:[{t:3}],s:"Автообновление"}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Чтение состояния хоста…"}},host:{t:0,b:{t:2,i:[{t:3}],s:"Хост"}},hostname:{t:0,b:{t:2,i:[{t:3}],s:"Имя хоста"}},distro:{t:0,b:{t:2,i:[{t:3}],s:"ОС"}},kernel:{t:0,b:{t:2,i:[{t:3}],s:"Ядро"}},uptime:{t:0,b:{t:2,i:[{t:3}],s:"Время работы"}},cpu:{t:0,b:{t:2,i:[{t:3}],s:"Процессор"}},temp:{t:0,b:{t:2,i:[{t:3}],s:"Температура"}},load:{t:0,b:{t:2,i:[{t:3}],s:"Нагрузка (1·5·15 мин)"}},cores:{t:0,b:{t:2,i:[{t:3}],s:"Ядра"}},throttled:{t:0,b:{t:2,i:[{t:3}],s:"Троттлинг"}},memory:{t:0,b:{t:2,i:[{t:3}],s:"Память"}},ram:{t:0,b:{t:2,i:[{t:3}],s:"ОЗУ"}},swap:{t:0,b:{t:2,i:[{t:3}],s:"Подкачка"}},disk:{t:0,b:{t:2,i:[{t:3}],s:"Диск"}},network:{t:0,b:{t:2,i:[{t:3}],s:"Сеть"}},iface:{t:0,b:{t:2,i:[{t:3}],s:"Интерфейс"}},ip:{t:0,b:{t:2,i:[{t:3}],s:"IP-адрес"}},ssid:{t:0,b:{t:2,i:[{t:3}],s:"Wi-Fi"}},signal:{t:0,b:{t:2,i:[{t:3}],s:"Сигнал"}},timeLocale:{t:0,b:{t:2,i:[{t:3}],s:"Время и локаль"}},timezone:{t:0,b:{t:2,i:[{t:3}],s:"Часовой пояс"}},ntp:{t:0,b:{t:2,i:[{t:3}],s:"Синхронизация часов"}},synced:{t:0,b:{t:2,i:[{t:3}],s:"Синхронизировано"}},syncing:{t:0,b:{t:2,i:[{t:3}],s:"Синхронизация…"}},ntpOff:{t:0,b:{t:2,i:[{t:3}],s:"Выключено"}},language:{t:0,b:{t:2,i:[{t:3}],s:"Язык"}},keymap:{t:0,b:{t:2,i:[{t:3}],s:"Раскладка"}},topProcesses:{t:0,b:{t:2,i:[{t:3}],s:"Самые нагружающие процессы"}},command:{t:0,b:{t:2,i:[{t:3}],s:"Команда"}},cpuPct:{t:0,b:{t:2,i:[{t:3}],s:"ЦП %"}},memPct:{t:0,b:{t:2,i:[{t:3}],s:"ОЗУ %"}},pid:{t:0,b:{t:2,i:[{t:3}],s:"PID"}}}}};export{t as default};
